import "./register.css";

export default function Register() {
  return (
    <div className="register">
      <div className="form glass">
        <h2>Register</h2>

        <input placeholder="Name" />
        <input placeholder="Email" />
        <input placeholder="Password" />

        <button>Sign Up</button>
      </div>
    </div>
  );
}
